module up_down_counter
    (
        input clk,
        input enable,
        input dir,
        input rst,
        output reg [2:0] count
    );

    reg [2:0] cnt_reg;

    always @(posedge clk) begin
        if (rst) begin
            cnt_reg <= 3'b000;
        end else if (enable) begin
            if (dir) begin
                cnt_reg <= cnt_reg + 1;
            end else begin
                cnt_reg <= cnt_reg - 1;
            end
        end
    end

    assign count = cnt_reg;

endmodule
